class Solution {
    // Function to find the distance of nearest 1 in the grid for each cell
    nearest(grid) {
        const n = grid.length;      // Number of rows
        const m = grid[0].length;   // Number of columns

        // Visited matrix
        const vis = Array.from({ length: n }, () => Array(m).fill(0));
        // Distance matrix
        const dist = Array.from({ length: n }, () => Array(m).fill(0));

        // Queue for BFS (will store [row, col, steps])
        const q = [];

        // Initialize queue with cells containing 1
        for (let i = 0; i < n; i++) {
            for (let j = 0; j < m; j++) {
                if (grid[i][j] === 1) {
                    q.push([i, j, 0]); // Push initial positions with 0 distance
                    vis[i][j] = 1;     // Mark as visited
                }
            }
        }

        // Directions: Up, Right, Down, Left
        const delRow = [-1, 0, 1, 0];
        const delCol = [0, 1, 0, -1];

        // BFS traversal
        while (q.length > 0) {
            const [row, col, steps] = q.shift(); // Dequeue
            dist[row][col] = steps; // Set distance for this cell

            // Explore all 4 directions
            for (let i = 0; i < 4; i++) {
                const nrow = row + delRow[i];
                const ncol = col + delCol[i];

                // Check if the next cell is valid and unvisited
                if (nrow >= 0 && nrow < n && ncol >= 0 && ncol < m && vis[nrow][ncol] === 0) {
                    vis[nrow][ncol] = 1; // Mark as visited
                    q.push([nrow, ncol, steps + 1]); // Enqueue with updated steps
                }
            }
        }

        return dist;
    }
}

// Driver code
